firmware_template.source:
#include "vl53l1x.h"
#include <Wire.h>
#include <VL53L1X.h>
static VL53L1X sensor;
static uint16_t _mm=0;static bool _timeout=false;static unsigned long _l=0;
void vl53l1x_setup(){Wire.begin();sensor.setTimeout(500);if(!sensor.init()){Serial.println("[vl53l1x] Fail!");return;}sensor.setDistanceMode(VL53L1X::Long);sensor.setMeasurementTimingBudget(50000);sensor.startContinuous(50);Serial.println("[vl53l1x] OK");}
void vl53l1x_loop(){if(millis()-_l<100)return;_l=millis();_mm=sensor.read();_timeout=sensor.timeoutOccurred();}
uint16_t vl53l1x_get_distance_mm(){return _mm;}
bool vl53l1x_timed_out(){return _timeout;}
